type Cell = number[];

function isNeighbor(a: Cell, b: Cell): boolean {
  const isSameCell = a[0] === b[0] && a[1] === b[1];
  return (
    !isSameCell && Math.abs(a[0] - b[0]) <= 1 && Math.abs(a[1] - b[1]) <= 1
  );
}

function countLiveNeighbors(cell: Cell, liveCells: Cell[]): number {
  return liveCells.filter((other) => isNeighbor(cell, other)).length;
}

export function nextGeneration(grid: Cell[]): Cell[] {
  return grid.filter((cell) => {
    const liveNeighbors = countLiveNeighbors(cell, grid);
    return liveNeighbors === 2 || liveNeighbors === 3;
  });
}
